package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	User string
	Text string
}

var comments = []Comment{
	{User: "Alice", Text: "<b>Great post!</b>"},
	{User: "Bob", Text: "<i>Very helpful.</i>"},
	{User: "Charlie", Text: "<u>Thanks!</u>"},
}

func handler(w http.ResponseWriter, r *http.Request) {
	tmpl := template.Must(template.New("comments").Parse(`
	<!DOCTYPE html>
	<html lang="en">
	<head>
		<meta charset="UTF-8">
		<title>Comments</title>
	</head>
	<body>
		<h1>Comments</h1>
		<ul>
			{{range .}}
				<li><strong>{{.User}}</strong>: {{.Text}}</li>
			{{end}}
		</ul>
	</body>
	</html>
	`))

	err := tmpl.Execute(w, comments)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}